1318→    private void markMessageAsRead(Account account, LocalMessage message) {
1319→        List<Long> messageIds = Collections.singletonList(message.getDatabaseId());
1320→        setFlagSynchronous(account, messageIds, Flag.SEEN, true, false);
1321→    }
