1207→    private void loadMessageRemoteSynchronous(Account account, long folderId, String messageServerId,
1208→            MessagingListener listener, boolean loadPartialFromSearch) {
1209→        try {
1210→            if (messageServerId.startsWith(K9.LOCAL_UID_PREFIX)) {
1211→                throw new IllegalArgumentException("Must not be called with a local UID");
1212→            }
1213→
1214→            MessageStore messageStore = messageStoreManager.getMessageStore(account);
1215→
1216→            String folderServerId = messageStore.getFolderServerId(folderId);
1217→            if (folderServerId == null) {
1218→                throw new IllegalStateException("Folder not found (ID: " + folderId + ")");
1219→            }
1220→
1221→            Backend backend = getBackend(account);
1222→
1223→            if (loadPartialFromSearch) {
1224→                SyncConfig syncConfig = createSyncConfig(account);
1225→                backend.downloadMessage(syncConfig, folderServerId, messageServerId);
1226→            } else {
1227→                backend.downloadCompleteMessage(folderServerId, messageServerId);
1228→            }
1229→
1230→            for (MessagingListener l : getListeners(listener)) {
1231→                l.loadMessageRemoteFinished(account, folderId, messageServerId);
1232→            }
1233→        } catch (Exception e) {
1234→            for (MessagingListener l : getListeners(listener)) {
1235→                l.loadMessageRemoteFailed(account, folderId, messageServerId, e);
1236→            }
1237→
1238→            notifyUserIfCertificateProblem(account, e, true);
1239→            Timber.e(e, "Error while loading remote message");
1240→        }
1241→    }
