1279→    public void markMessageAsOpened(Account account, LocalMessage message) {
1280→        threadPool.execute(() ->
1281→            notificationController.removeNewMailNotification(account, message.makeMessageReference())
1282→        );
1283→
1284→        if (message.isSet(Flag.SEEN)) {
1285→            // Nothing to do if the message is already marked as read
1286→            return;
1287→        }
1288→
1289→        boolean markMessageAsRead = account.isMarkMessageAsReadOnView();
1290→        if (markMessageAsRead) {
1291→            // Mark the message itself as read right away
1292→            try {
1293→                message.setFlagInternal(Flag.SEEN, true);
1294→            } catch (MessagingException e) {
1295→                Timber.e(e, "Error while marking message as read");
1296→            }
1297→
1298→            // Also mark the message as read in the cache
1299→            List<Long> messageIds = Collections.singletonList(message.getDatabaseId());
1300→            setFlagInCache(account, messageIds, Flag.SEEN, true);
1301→        }
1302→
1303→        putBackground("markMessageAsOpened", null, () -> {
1304→            markMessageAsOpenedBlocking(account, message, markMessageAsRead);
1305→        });
1306→    }
1307→
1308→    private void markMessageAsOpenedBlocking(Account account, LocalMessage message, boolean markMessageAsRead) {
1309→        if (markMessageAsRead) {
1310→            markMessageAsRead(account, message);
1311→        } else {
1312→            // Marking a message as read will automatically mark it as "not new". But if we don't mark the message
1313→            // as read on opening, we have to manually mark it as "not new".
1314→            markMessageAsNotNew(account, message);
1315→        }
1316→    }
